-- Employee Handbook content: one row per section, structured for in-app
-- rendering (TOC, search) instead of a static PDF link. Seeded once from
-- handbook_content.json (extracted from rebuild_handbook.py — see
-- ~/Desktop/Gothamhalal PDFs/company guide/extract_content.py). Re-seeding
-- after a content edit should go through the owner-only upsert function,
-- not a raw migration, once Phase 3 (acknowledgment) ships.

CREATE TABLE public.handbook_sections (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  part_number integer NOT NULL,
  part_title text NOT NULL,
  section_number integer NOT NULL,
  section_title text NOT NULL,
  body_blocks jsonb NOT NULL,
  is_policy boolean NOT NULL DEFAULT false,
  display_order integer NOT NULL,
  version integer NOT NULL DEFAULT 1,
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX handbook_sections_order_idx ON public.handbook_sections(display_order);
CREATE INDEX handbook_sections_policy_idx ON public.handbook_sections(is_policy);

GRANT SELECT ON public.handbook_sections TO authenticated;
GRANT ALL ON public.handbook_sections TO service_role;
ALTER TABLE public.handbook_sections ENABLE ROW LEVEL SECURITY;

-- Every authenticated role (owner down to cashier) reads the full handbook —
-- this is intentionally NOT role-gated, per the locked product decision that
-- every employee gets full handbook access. Writes happen only through the
-- owner-only upsertHandbookSection() server function using the user JWT
-- client (RLS still applies there too — there is deliberately no INSERT/
-- UPDATE policy here yet; that arrives with the edit UI in a later phase).
CREATE POLICY "handbook_sections read all" ON public.handbook_sections
  FOR SELECT TO authenticated USING (true);

INSERT INTO public.handbook_sections
  (part_number, part_title, section_number, section_title, body_blocks, is_policy, display_order)
VALUES
  (1, 'COMPANY FOUNDATION', 1, 'Company Mission and Values', '[{"type": "paragraph", "text": "<b>Our Mission</b>"}, {"type": "paragraph", "text": "Gothamhalal exists to serve the best halal smash burgers in New York with excellence, integrity, and community at the center of everything we do. We are committed to delivering a product our customers trust, in an environment where our team is proud to work."}, {"type": "paragraph", "text": "<b>Our Values</b>"}, {"type": "other", "role": null, "text": "Value"}, {"type": "other", "role": null, "text": "What It Means at Gothamhalal"}, {"type": "other", "role": null, "text": "Quality"}, {"type": "other", "role": null, "text": "Every burger, every drink, every interaction must meet the Gothamhalal standard. Average is not acceptable. We take pride in doing things right the first time, every time."}, {"type": "other", "role": null, "text": "Halal Integrity"}, {"type": "other", "role": null, "text": "Our halal certification is the foundation of this brand. Every team member is responsible for protecting it. There is zero tolerance for compromising halal standards."}, {"type": "other", "role": null, "text": "Teamwork"}, {"type": "other", "role": null, "text": "No individual wins alone. We communicate, we support each other, and we work as one unit from open to close. The team is always more important than any single person."}, {"type": "other", "role": null, "text": "Respect"}, {"type": "other", "role": null, "text": "Every person — customer, coworker, or manager — deserves to be treated with dignity. We do not tolerate disrespect in any form at Gothamhalal."}, {"type": "other", "role": null, "text": "Excellence"}, {"type": "other", "role": null, "text": "We pursue excellence in our food, our speed, our cleanliness, and our hospitality. We hold ourselves and each other to the highest standard because that is what Gothamhalal represents."}, {"type": "table", "rows": [["Value", "What It Means at Gothamhalal"], ["Quality", "Every burger, every drink, every interaction must meet the Gothamhalal standard. Average is not acceptable. We take pride in doing things right the first time, every time."], ["Halal Integrity", "Our halal certification is the foundation of this brand. Every team member is responsible for protecting it. There is zero tolerance for compromising halal standards."], ["Teamwork", "No individual wins alone. We communicate, we support each other, and we work as one unit from open to close. The team is always more important than any single person."], ["Respect", "Every person — customer, coworker, or manager — deserves to be treated with dignity. We do not tolerate disrespect in any form at Gothamhalal."], ["Excellence", "We pursue excellence in our food, our speed, our cleanliness, and our hospitality. We hold ourselves and each other to the highest standard because that is what Gothamhalal represents."]]}]'::jsonb, false, 1),
  (1, 'COMPANY FOUNDATION', 2, 'Halal Food Commitment Statement', '[{"type": "paragraph", "text": "<b>What Halal Means</b>"}, {"type": "paragraph", "text": "Halal is an Arabic word meaning \"permissible\" under Islamic law. For food, halal certification means that all ingredients, preparation methods, and handling practices comply with Islamic dietary guidelines. This includes:"}, {"type": "bullet", "text": "All meat is sourced from animals slaughtered in accordance with Islamic law (Zabiha)"}, {"type": "bullet", "text": "No pork, pork by-products, or alcohol-based ingredients are used in any product"}, {"type": "bullet", "text": "All suppliers and ingredients are vetted and certified halal"}, {"type": "bullet", "text": "Cross-contamination with non-halal products is prevented through strict kitchen protocols"}, {"type": "paragraph", "text": "<b>Our Commitment</b>"}, {"type": "paragraph", "text": "Gothamhalal has built its entire brand on halal integrity. Our customers choose us because they trust us. That trust must never be broken. Every team member at every level is responsible for upholding halal standards during every shift."}, {"type": "paragraph", "text": "<b>Non-Negotiable Halal Standards:</b>"}, {"type": "bullet", "text": "Only use approved, certified halal ingredients. Never substitute ingredients without manager approval."}, {"type": "bullet", "text": "Keep all halal food products separate from any non-certified items at all times."}, {"type": "bullet", "text": "Immediately report any potential halal compromise to your manager — do not attempt to resolve it yourself."}, {"type": "bullet", "text": "Never bring outside food or personal food items into the kitchen or food prep area."}, {"type": "bullet", "text": "All new food products introduced to the menu must have halal certification documentation on file."}, {"type": "note", "text": "Tampering with or knowingly compromising halal food standards is an immediate termination offense. This is not subject to the progressive discipline process."}]'::jsonb, false, 2),
  (1, 'COMPANY FOUNDATION', 3, 'Equal Opportunity Employment', '[{"type": "paragraph", "text": "Gothamhalal is an equal opportunity employer. We are committed to providing equal employment opportunities to all employees and applicants without regard to race, color, religion, national origin, sex, gender identity, sexual orientation, age, disability, pregnancy, marital status, military status, or any other characteristic protected by New York State Human Rights Law, New York City Human Rights Law (where applicable), and applicable federal law including Title VII of the Civil Rights Act, the Americans with Disabilities Act, and the Age Discrimination in Employment Act."}, {"type": "paragraph", "text": "This policy applies to all aspects of employment including hiring, promotion, demotion, compensation, benefits, training, layoff, and termination. Gothamhalal will make reasonable accommodations for qualified individuals with disabilities and for sincerely held religious beliefs where doing so does not create an undue hardship."}, {"type": "paragraph", "text": "Any employee who believes they have been subjected to discrimination should report it immediately to Ahmed Mario Almugannahi, Director of Operations, at mario@gothamhalal.com or to Founder & CEO Rami Ali and Co-Founder & CEO Talha Shahid, at hello@gothamhalal.com. All reports will be investigated promptly and confidentially."}]'::jsonb, false, 3),
  (1, 'COMPANY FOUNDATION', 4, 'At-Will Employment', '[{"type": "paragraph", "text": "Employment at Gothamhalal is at-will. This means that either you or Gothamhalal may end the employment relationship at any time, for any reason or no reason, with or without notice, as permitted by New York State law. Nothing in this handbook, in any verbal statement, or in any other company document creates a contract of employment or alters the at-will nature of your employment."}, {"type": "paragraph", "text": "The progressive discipline policy described in this handbook reflects Gothamhalal''s general approach to corrective action but does not limit the company''s right to terminate employment at will for any reason, including reasons not covered in that policy."}]'::jsonb, false, 4),
  (2, 'EMPLOYMENT POLICIES', 5, '60-Day Probationary Period', '[{"type": "paragraph", "text": "All new employees at Gothamhalal are subject to a 60-day probationary period beginning on their first day of employment. This period allows both the employee and Gothamhalal to evaluate fit, performance, and commitment."}, {"type": "paragraph", "text": "During the probationary period:"}, {"type": "bullet", "text": "Your performance, attendance, attitude, and adherence to standards will be closely evaluated"}, {"type": "bullet", "text": "You will complete all required training and demonstrate competency in your role"}, {"type": "bullet", "text": "A 30-day check-in will be conducted by your manager to discuss performance"}, {"type": "bullet", "text": "A 60-day evaluation will be conducted to determine whether you successfully complete the probationary period"}, {"type": "bullet", "text": "Employment may be ended at any time during the probationary period without following the progressive discipline process"}, {"type": "paragraph", "text": "Successful completion of the probationary period does not guarantee continued employment and does not alter your at-will employment status."}]'::jsonb, true, 5),
  (2, 'EMPLOYMENT POLICIES', 6, 'Anti-Harassment and Anti-Discrimination Policy', '[{"type": "paragraph", "text": "<b>Policy Statement</b>"}, {"type": "paragraph", "text": "Gothamhalal is committed to providing a workplace free from harassment and discrimination. All employees have the right to work in an environment where they are treated with dignity and respect. Harassment or discrimination of any kind — based on race, color, religion, sex, national origin, age, disability, sexual orientation, gender identity, marital status, military status, or any other protected characteristic — will not be tolerated and will result in serious disciplinary action up to and including immediate termination."}, {"type": "paragraph", "text": "<b>What Constitutes Harassment</b>"}, {"type": "paragraph", "text": "Harassment includes but is not limited to:"}, {"type": "bullet", "text": "Unwelcome verbal conduct: slurs, jokes, derogatory comments, offensive name-calling, or threats based on a protected characteristic"}, {"type": "bullet", "text": "Unwelcome physical conduct: touching, grabbing, blocking movement, or physical intimidation"}, {"type": "bullet", "text": "Sexual harassment: unwanted sexual advances, requests for sexual favors, sexual comments, display of sexually explicit material, or any conduct of a sexual nature that creates a hostile work environment or is made a condition of employment"}, {"type": "bullet", "text": "Visual harassment: posting, displaying, or sharing offensive images, messages, or content in the workplace or via any device used at work"}, {"type": "bullet", "text": "Cyberbullying or harassment via text, social media, or any electronic communication related to the workplace"}, {"type": "paragraph", "text": "<b>Sexual Harassment — New York State Requirements</b>"}, {"type": "paragraph", "text": "New York State law requires all employers to have a written sexual harassment prevention policy and provide annual training to all employees. Gothamhalal complies fully with these requirements. All employees must complete sexual harassment prevention training annually. Supervisors and managers have heightened responsibilities and will receive additional training."}, {"type": "paragraph", "text": "Under New York State law, sexual harassment includes harassment by any person — supervisor, coworker, customer, or vendor. If a customer harasses you, report it to your manager immediately. Gothamhalal will take action to protect you."}, {"type": "paragraph", "text": "<b>Reporting Procedure</b>"}, {"type": "bullet", "text": "1. Report it immediately to Ahmed Mario Almugannahi, Director of Operations, at mario@gothamhalal.com"}, {"type": "bullet", "text": "2. If the conduct involves your direct manager or if you are uncomfortable reporting to Ahmed Mario, report directly to Founder & CEO Rami Ali or Co-Founder & CEO Talha Shahid, at hello@gothamhalal.com"}, {"type": "bullet", "text": "3. Reports may be made verbally or in writing. Written reports are encouraged for documentation purposes."}, {"type": "bullet", "text": "4. All reports will be investigated promptly, thoroughly, and as confidentially as possible"}, {"type": "paragraph", "text": "<b>Non-Retaliation</b>"}, {"type": "paragraph", "text": "Gothamhalal strictly prohibits retaliation against any employee who reports harassment or discrimination in good faith or who participates in any investigation. Retaliation is itself a violation of this policy and will result in discipline up to and including termination."}, {"type": "paragraph", "text": "<b>Consequences</b>"}, {"type": "paragraph", "text": "Any employee found to have engaged in harassment or discrimination will be subject to disciplinary action up to and including immediate termination, regardless of their position or tenure."}]'::jsonb, true, 6),
  (2, 'EMPLOYMENT POLICIES', 7, 'Workplace Violence Prevention Policy (NY HERO Act)', '[{"type": "paragraph", "text": "Gothamhalal is committed to maintaining a workplace free from violence, threats of violence, intimidation, bullying, and any conduct that creates a reasonable fear of harm. This policy is established in compliance with the New York State HERO Act and New York Labor Law."}, {"type": "paragraph", "text": "<b>Prohibited Conduct</b>"}, {"type": "bullet", "text": "Physical assault, fighting, or threatening any person in or around the workplace"}, {"type": "bullet", "text": "Possession of any weapon on company property or while in uniform"}, {"type": "bullet", "text": "Threatening language, whether verbal, written, or electronic"}, {"type": "bullet", "text": "Intimidating, coercing, or bullying any employee, customer, or visitor"}, {"type": "bullet", "text": "Any behavior that a reasonable person would interpret as threatening or dangerous"}, {"type": "paragraph", "text": "<b>Reporting</b>"}, {"type": "paragraph", "text": "Any incident of workplace violence, threatened violence, or behavior that may escalate to violence must be reported immediately to your manager or to Ahmed Mario Almugannahi. If there is an immediate threat to safety, call 911 first. Do not attempt to physically intervene in a violent situation — your safety is the priority."}, {"type": "paragraph", "text": "<b>Consequences</b>"}, {"type": "paragraph", "text": "Engaging in workplace violence or making threats of violence is an immediate termination offense at Gothamhalal. There is no progressive discipline for this category of conduct."}]'::jsonb, true, 7),
  (2, 'EMPLOYMENT POLICIES', 8, 'Confidentiality Policy', '[{"type": "paragraph", "text": "As a Gothamhalal team member, you may have access to confidential business information including customer data, supplier relationships, recipes, pricing, financial information, operational systems, and personnel information. You are required to keep all such information strictly confidential during and after your employment."}, {"type": "paragraph", "text": "You may not share, post, photograph, record, copy, or disclose any proprietary business information without express written authorization from management. Violation of this policy may result in immediate termination and may expose you to legal liability."}]'::jsonb, true, 8),
  (3, 'STANDARDS OF CONDUCT', 9, 'Attendance and Punctuality', '[{"type": "paragraph", "text": "Reliable attendance is a fundamental requirement of employment at Gothamhalal. Our operation depends on every team member showing up, on time and ready to work. When you do not show up or arrive late without warning, it creates hardship for your coworkers and impacts the customer experience."}, {"type": "paragraph", "text": "<b>Punctuality Standard</b>"}, {"type": "paragraph", "text": "You are expected to arrive at work at your scheduled start time, changed into uniform and ready to begin your shift. Arriving at the start time only to then change and prepare means you are late. The shift clock starts when you are station-ready."}, {"type": "paragraph", "text": "Tardiness Policy: Three (3) instances of tardiness within any rolling 30-day period will result in a written warning under the progressive discipline system."}, {"type": "paragraph", "text": "<b>Attendance Expectations</b>"}, {"type": "bullet", "text": "Employees are expected to work all scheduled shifts"}, {"type": "bullet", "text": "Schedules are posted weekly by the manager — you are responsible for knowing your schedule"}, {"type": "bullet", "text": "Excessive absenteeism — defined as more than two unexcused absences in any 30-day period — may result in progressive discipline up to and including termination"}, {"type": "bullet", "text": "Patterns of calling out on specific days (e.g., consistently calling out on Fridays or weekends) are considered attendance violations and will be addressed through progressive discipline"}, {"type": "other", "role": null, "text": "Excused Absence"}, {"type": "other", "role": null, "text": "Unexcused Absence"}, {"type": "other", "role": null, "text": "Documented illness or medical appointment"}, {"type": "other", "role": null, "text": "No call, no show"}, {"type": "other", "role": null, "text": "Family emergency (documented where possible)"}, {"type": "other", "role": null, "text": "Calling out less than 2 hours before shift"}, {"type": "other", "role": null, "text": "Approved paid sick leave use"}, {"type": "other", "role": null, "text": "Leaving shift early without manager approval"}, {"type": "other", "role": null, "text": "Pre-approved time off"}, {"type": "other", "role": null, "text": "Any absence not reported per call-out procedure"}, {"type": "table", "rows": [["Excused Absence", "Unexcused Absence"], ["Documented illness or medical appointment", "No call, no show"], ["Family emergency (documented where possible)", "Calling out less than 2 hours before shift"], ["Approved paid sick leave use", "Leaving shift early without manager approval"], ["Pre-approved time off", "Any absence not reported per call-out procedure"]]}]'::jsonb, true, 9),
  (3, 'STANDARDS OF CONDUCT', 10, 'Call-Out Procedure', '[{"type": "paragraph", "text": "If you cannot report to work for any reason, you must follow this procedure without exception:"}, {"type": "bullet", "text": "1. Call your manager directly — at minimum 2 hours before your scheduled shift start time"}, {"type": "bullet", "text": "2. Do not text, do not message through social media, and do not ask a coworker to relay the message. You must make direct contact with your manager by phone call."}, {"type": "bullet", "text": "3. If you cannot reach your manager, call the general company contact and leave a voicemail, then follow up by text to document your attempt."}, {"type": "bullet", "text": "4. Calling out does not guarantee approval of the absence — the manager will determine whether it is excused."}, {"type": "note", "text": "No Call / No Show (NCNS): Failing to appear for a scheduled shift without calling your manager at least 2 hours in advance is a No Call / No Show. A first NCNS results in a written warning. A second NCNS within any 12-month period is an immediate termination offense."}]'::jsonb, true, 10),
  (3, 'STANDARDS OF CONDUCT', 11, 'Dress Code and Uniform Policy', '[{"type": "paragraph", "text": "<b>Gothamhalal Uniform</b>"}, {"type": "paragraph", "text": "Gothamhalal provides a branded uniform to all team members at no cost. The uniform is property of Gothamhalal and must be returned upon separation of employment. Wearing the uniform is mandatory for all shifts."}, {"type": "other", "role": null, "text": "Uniform Item"}, {"type": "other", "role": null, "text": "Standard"}, {"type": "other", "role": null, "text": "Gothamhalal Shirt / Top"}, {"type": "other", "role": null, "text": "Company-provided branded top. Must be clean, unwrinkled, and free of stains. No personal clothing visible beneath except solid-colored undershirts."}, {"type": "other", "role": null, "text": "Bottoms"}, {"type": "other", "role": null, "text": "Clean, dark-colored pants or jeans. No rips, tears, or graphic print. No athletic shorts or sweatpants."}, {"type": "other", "role": null, "text": "Footwear"}, {"type": "other", "role": null, "text": "Non-slip, closed-toe shoes are required in all kitchen areas. No sandals, flip flops, slides, or heels. Non-slip shoes are your responsibility."}, {"type": "other", "role": null, "text": "Hair"}, {"type": "other", "role": null, "text": "All hair must be covered or restrained while working in the kitchen or food prep area. Hats, nets, or head coverings provided by or approved by management are acceptable."}, {"type": "other", "role": null, "text": "Apron"}, {"type": "other", "role": null, "text": "Aprons are provided. Wear your apron in the kitchen and food prep area at all times during service."}, {"type": "table", "rows": [["Uniform Item", "Standard"], ["Gothamhalal Shirt / Top", "Company-provided branded top. Must be clean, unwrinkled, and free of stains. No personal clothing visible beneath except solid-colored undershirts."], ["Bottoms", "Clean, dark-colored pants or jeans. No rips, tears, or graphic print. No athletic shorts or sweatpants."], ["Footwear", "Non-slip, closed-toe shoes are required in all kitchen areas. No sandals, flip flops, slides, or heels. Non-slip shoes are your responsibility."], ["Hair", "All hair must be covered or restrained while working in the kitchen or food prep area. Hats, nets, or head coverings provided by or approved by management are acceptable."], ["Apron", "Aprons are provided. Wear your apron in the kitchen and food prep area at all times during service."]]}, {"type": "paragraph", "text": "<b>Appearance Standards</b>"}, {"type": "bullet", "text": "Uniforms must be clean, pressed, and presentable at the start of every shift"}, {"type": "bullet", "text": "No excessive jewelry that poses a food safety risk — rings, bracelets, and dangling earrings must be removed in food prep areas"}, {"type": "bullet", "text": "No facial tattoos. Tattoos on other areas of the body that are covered by the uniform are permitted."}, {"type": "bullet", "text": "Visible tattoos on arms or hands must be professional in appearance. Management reserves the right to require covering of any tattoo deemed offensive or inappropriate."}, {"type": "bullet", "text": "Nails must be clean and trimmed. No nail polish or acrylic nails in food handling positions."}, {"type": "bullet", "text": "Do not wear your Gothamhalal uniform outside of work except for direct transit to and from your shift"}]'::jsonb, true, 11),
  (3, 'STANDARDS OF CONDUCT', 12, 'Personal Hygiene Standards', '[{"type": "paragraph", "text": "As a food service employee, your personal hygiene directly impacts the safety and quality of our product. The following standards are required of all team members:"}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Handwashing</font></b>  Wash hands thoroughly with soap and warm water for a minimum of 20 seconds before beginning your shift, after handling raw meat, after touching your face or hair, after using the restroom, after taking out trash, after handling money, and after any activity that may contaminate your hands."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Gloves</font></b>  Single-use gloves must be worn when handling ready-to-eat food. Change gloves when switching between tasks, after touching your face, and any time contamination may have occurred."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Illness</font></b>  Do not report to work if you have symptoms of vomiting, diarrhea, jaundice, or open infected wounds. These are reportable food handler conditions under New York State law. If you become ill during a shift, notify your manager immediately."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Bathing</font></b>  Report to work clean and appropriately groomed. Excessive use of perfume or cologne is not appropriate in a food service environment."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Cuts and wounds</font></b>  All cuts, wounds, or open sores on hands or arms must be covered with a waterproof bandage and a food-safe glove. Report any hand injuries to your manager before beginning food handling."}]'::jsonb, true, 12),
  (3, 'STANDARDS OF CONDUCT', 13, 'Cell Phone Policy', '[{"type": "paragraph", "text": "Gothamhalal maintains a strict no-cell-phone policy on the floor during active shifts. Attention is part of hospitality, and distraction from your phone is not acceptable while you are on the clock and serving customers."}, {"type": "paragraph", "text": "<b>Cell Phone Rules — Non-Negotiable:</b>"}, {"type": "bullet", "text": "Your personal cell phone must be stored in the back of house — in your bag, locker, or designated storage area — before your shift begins."}, {"type": "bullet", "text": "Cell phones are not permitted on the service floor, at any station, or in any customer-facing area during your shift."}, {"type": "bullet", "text": "Cell phone use is permitted on designated breaks only, in the back of house or break area."}, {"type": "bullet", "text": "Emergency calls must be taken in the back with manager notification. If you are expecting an emergency call, notify your manager at the start of your shift."}, {"type": "bullet", "text": "Smart watches may not be used to read or respond to messages during active service."}, {"type": "paragraph", "text": "First violation will result in a verbal warning and documented coaching. Second violation will be treated as a Strike 1 written warning under the progressive discipline policy. The phone will be removed from the floor regardless."}]'::jsonb, true, 13),
  (3, 'STANDARDS OF CONDUCT', 14, 'Social Media Policy', '[{"type": "paragraph", "text": "Gothamhalal''s brand, products, operations, and team members may not be recorded, photographed, or posted without express management approval. This policy protects our brand, our team''s privacy, our proprietary operations, and our customer experience."}, {"type": "bullet", "text": "No filming, photographing, or live streaming inside the restaurant, kitchen, or trailer during your shift"}, {"type": "bullet", "text": "Do not post about Gothamhalal operations, food, team members, internal issues, or customer information without written management approval"}, {"type": "bullet", "text": "You may not post anything that represents Gothamhalal in a negative, misleading, or unprofessional light — including venting about coworkers, customers, or management on personal social media"}, {"type": "bullet", "text": "Approved posts for personal social media must not include confidential operational information, customer images without consent, or financial data"}, {"type": "bullet", "text": "Violations of this policy may result in immediate termination depending on severity"}]'::jsonb, true, 14),
  (3, 'STANDARDS OF CONDUCT', 15, 'Smoking and Vaping Policy', '[{"type": "paragraph", "text": "Gothamhalal maintains a strict no-smoking and no-vaping policy on all company premises and while in uniform."}, {"type": "bullet", "text": "Smoking, vaping, and use of any tobacco or nicotine product is prohibited on all company premises including the restaurant, trailer, parking areas, and any areas adjacent to the operation"}, {"type": "bullet", "text": "Smoking or vaping while wearing the Gothamhalal uniform — at any location — is prohibited"}, {"type": "bullet", "text": "If you smoke on breaks, you must change out of your uniform or cover it completely before doing so, and you must wash your hands and ensure your uniform is free of odor before returning to service"}, {"type": "bullet", "text": "This policy applies at all times while on the clock"}]'::jsonb, true, 15),
  (3, 'STANDARDS OF CONDUCT', 16, 'Code of Conduct', '[{"type": "paragraph", "text": "Every Gothamhalal employee is expected to conduct themselves with professionalism, integrity, and respect at all times."}, {"type": "paragraph", "text": "<b>Professionalism</b>"}, {"type": "bullet", "text": "Treat every customer with warmth and efficiency. The customer''s experience is your primary responsibility while on the floor."}, {"type": "bullet", "text": "Maintain a positive and cooperative attitude with coworkers regardless of personal relationships outside of work"}, {"type": "bullet", "text": "Workplace drama, gossip about coworkers, or negative conversation about management on the floor is not acceptable and will be addressed through progressive discipline"}, {"type": "bullet", "text": "Disagreements with management or coworkers must be addressed professionally and privately — never in front of customers"}, {"type": "paragraph", "text": "<b>Integrity</b>"}, {"type": "bullet", "text": "Handle all cash, inventory, and company property with honesty. Any form of theft — including consuming product without authorization, undercounting the drawer, or giving unauthorized discounts — is an immediate termination offense."}, {"type": "bullet", "text": "Be honest with your manager. If you make a mistake, report it. Bad news reported early is fixable. Mistakes discovered later because they were hidden are not."}, {"type": "bullet", "text": "Do not falsify any company records, time records, or documents under any circumstances."}, {"type": "paragraph", "text": "<b>Downtime Expectations</b>"}, {"type": "paragraph", "text": "There is always work to be done at Gothamhalal. When service volume is low, team members are expected to:"}, {"type": "bullet", "text": "Clean — wipe stations, surfaces, equipment, and floors"}, {"type": "bullet", "text": "Prep — restock supplies, replenish ingredients, prepare for the next rush"}, {"type": "bullet", "text": "Support — assist teammates who may need help at their station"}, {"type": "bullet", "text": "Improve — review SOP materials and ask questions to become better at your role"}, {"type": "paragraph", "text": "Standing around waiting to be told what to do during downtime reflects poor work ethic and will be noted in performance reviews."}]'::jsonb, true, 16),
  (4, 'OPERATIONS AND COMPENSATION', 17, 'Customer Service Standards', '[{"type": "paragraph", "text": "At Gothamhalal, hospitality is not an afterthought — it is part of the product. Every customer interaction must be warm, efficient, and professional. The following standards are non-negotiable."}, {"type": "other", "role": null, "text": "Standard"}, {"type": "other", "role": null, "text": "Expectation"}, {"type": "other", "role": null, "text": "Target"}, {"type": "other", "role": null, "text": "Greeting"}, {"type": "other", "role": null, "text": "\"Hello, welcome to Gothamhalal. How may I help you today?\""}, {"type": "other", "role": null, "text": "Within 5 seconds of customer approach"}, {"type": "other", "role": null, "text": "Order Entry"}, {"type": "other", "role": null, "text": "Repeat order back to customer to confirm."}, {"type": "other", "role": null, "text": "Under 2 minutes"}, {"type": "other", "role": null, "text": "Upsell"}, {"type": "other", "role": null, "text": "\"Would you like to make that a combo or add one of our drinks?\""}, {"type": "other", "role": null, "text": "Every order, every time"}, {"type": "other", "role": null, "text": "Wait Update"}, {"type": "other", "role": null, "text": "\"Thank you for waiting — your order is being finished now.\""}, {"type": "other", "role": null, "text": "If wait exceeds 10 minutes"}, {"type": "other", "role": null, "text": "Pickup"}, {"type": "other", "role": null, "text": "Confirm payment, confirm order, make eye contact. \"Thank you for choosing Gothamhalal — enjoy your meal.\""}, {"type": "other", "role": null, "text": "Under 30 seconds from order ready"}, {"type": "other", "role": null, "text": "Complaint Handling"}, {"type": "other", "role": null, "text": "Acknowledge, apologize, resolve. Never argue with a customer. Escalate to manager if needed."}, {"type": "other", "role": null, "text": "Immediate acknowledgment"}, {"type": "table", "rows": [["Standard", "Expectation", "Target"], ["Greeting", "\"Hello, welcome to Gothamhalal. How may I help you today?\"", "Within 5 seconds of customer approach"], ["Order Entry", "Repeat order back to customer to confirm.", "Under 2 minutes"], ["Upsell", "\"Would you like to make that a combo or add one of our drinks?\"", "Every order, every time"], ["Wait Update", "\"Thank you for waiting — your order is being finished now.\"", "If wait exceeds 10 minutes"], ["Pickup", "Confirm payment, confirm order, make eye contact. \"Thank you for choosing Gothamhalal — enjoy your meal.\"", "Under 30 seconds from order ready"], ["Complaint Handling", "Acknowledge, apologize, resolve. Never argue with a customer. Escalate to manager if needed.", "Immediate acknowledgment"]]}, {"type": "paragraph", "text": "<b>Handling Customer Complaints</b>"}, {"type": "bullet", "text": "1. Listen — Let the customer speak without interruption. Do not become defensive."}, {"type": "bullet", "text": "2. Acknowledge — \"I understand, I''m sorry for the inconvenience.\""}, {"type": "bullet", "text": "3. Resolve — Offer a solution: remake the item, issue a refund, or provide a complementary item per manager authorization."}, {"type": "bullet", "text": "4. Escalate — If the situation is beyond your authority or the customer is becoming hostile, call your manager immediately. Do not attempt to manage a hostile customer alone."}, {"type": "bullet", "text": "5. Document — All complaints must be logged in the Customer Complaint Log."}]'::jsonb, true, 17),
  (4, 'OPERATIONS AND COMPENSATION', 18, 'Cash Handling Policy', '[{"type": "paragraph", "text": "Cash handling at Gothamhalal requires complete accuracy and accountability. Every team member who handles cash is personally responsible for their drawer."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Assigned Drawers Only</font></b>  Each cashier is responsible for their own drawer. Do not allow another employee to use your drawer without manager authorization."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Opening Count</font></b>  Count your drawer at the beginning of every shift and confirm the opening balance with your manager. Document and sign the Cash Reconciliation Form."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Closing Count</font></b>  Count and reconcile your drawer at the end of every shift before leaving. Any discrepancy must be reported to your manager immediately."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>Discrepancies</font></b>  Cash shortages or overages must be reported to your manager at the end of every shift without exception. A pattern of shortages will trigger a performance investigation."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>No Personal Use</font></b>  Under no circumstances may you borrow from or use the cash drawer for any personal transaction. This is an immediate termination offense."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>No Open Drawer</font></b>  The cash drawer must be closed between every transaction. Never leave the drawer open and unattended."}]'::jsonb, true, 18),
  (4, 'OPERATIONS AND COMPENSATION', 19, 'Tip Pooling Policy', '[{"type": "paragraph", "text": "<b>Policy Overview</b>"}, {"type": "paragraph", "text": "Gothamhalal operates a mandatory tip pool for all employees working each shift. All tips collected — whether cash tips left by customers or tips added through the POS system — are pooled and distributed equally among all employees who worked that shift."}, {"type": "paragraph", "text": "<b>How It Works</b>"}, {"type": "bullet", "text": "All tips are collected and tracked throughout each shift"}, {"type": "bullet", "text": "At the end of each shift, total tips are divided equally by the number of employees who worked that shift"}, {"type": "bullet", "text": "Each participating employee receives an equal share regardless of position"}, {"type": "bullet", "text": "Tip distribution records will be maintained and provided to employees upon request"}, {"type": "paragraph", "text": "<b>Manager Participation — New York State Law</b>"}, {"type": "paragraph", "text": "Under New York Labor Law Section 196-d, managers and supervisors who regularly perform the same work as tipped employees — such as working the register, assembling orders, or performing front-of-house service — may participate in the tip pool for the hours in which they perform non-supervisory work. Managers who are solely performing supervisory duties during a shift will not participate in the tip pool for that shift. Tip pool participation by managers will be documented and transparently communicated to the team."}, {"type": "paragraph", "text": "<b>Effective Date:</b> This tip pool policy is effective January 1, 2025 and applies to all Gothamhalal locations."}, {"type": "paragraph", "text": "<b>Non-Retaliation</b>"}, {"type": "paragraph", "text": "No employee will be retaliated against for questioning or raising concerns about tip pool practices. Any concern about tip distribution should be brought directly to Ahmed Mario Almugannahi at mario@gothamhalal.com."}]'::jsonb, true, 19),
  (4, 'OPERATIONS AND COMPENSATION', 20, 'Work Schedules and Shifts', '[{"type": "other", "role": null, "text": "Shift"}, {"type": "other", "role": null, "text": "Hours"}, {"type": "other", "role": null, "text": "Total Hours"}, {"type": "other", "role": null, "text": "Morning Shift"}, {"type": "other", "role": null, "text": "11:00 AM – 4:00 PM"}, {"type": "other", "role": null, "text": "5 hours"}, {"type": "other", "role": null, "text": "Evening Shift"}, {"type": "other", "role": null, "text": "4:00 PM – 12:00 AM (Midnight)"}, {"type": "other", "role": null, "text": "8 hours"}, {"type": "other", "role": null, "text": "Friday (Evening Only)"}, {"type": "other", "role": null, "text": "4:00 PM – 12:00 AM (Midnight)"}, {"type": "other", "role": null, "text": "8 hours"}, {"type": "table", "rows": [["Shift", "Hours", "Total Hours"], ["Morning Shift", "11:00 AM – 4:00 PM", "5 hours"], ["Evening Shift", "4:00 PM – 12:00 AM (Midnight)", "8 hours"], ["Friday (Evening Only)", "4:00 PM – 12:00 AM (Midnight)", "8 hours"]]}, {"type": "bullet", "text": "Employees are scheduled to work 5 days per week. During operating weeks that include Friday service, some employees may be scheduled for 6 days."}, {"type": "bullet", "text": "Weekly schedules are posted by the manager no later than 72 hours before the start of the work week. It is your responsibility to check your schedule."}, {"type": "bullet", "text": "If you have a schedule conflict, notify your manager as early as possible — not the day of your shift."}, {"type": "bullet", "text": "Shift swaps require manager approval. Do not swap shifts without manager knowledge and written authorization."}]'::jsonb, true, 20),
  (4, 'OPERATIONS AND COMPENSATION', 21, 'Break Policy', '[{"type": "paragraph", "text": "Gothamhalal complies with all New York State labor law requirements for meal and rest breaks."}, {"type": "other", "role": null, "text": "Shift Length"}, {"type": "other", "role": null, "text": "Break Entitlement"}, {"type": "other", "role": null, "text": "Paid/Unpaid"}, {"type": "other", "role": null, "text": "Shifts over 6 hours"}, {"type": "other", "role": null, "text": "1 unpaid 30-minute meal break"}, {"type": "other", "role": null, "text": "Unpaid"}, {"type": "other", "role": null, "text": "Shifts between 5–6 hours (starting before 11 AM and extending past 2 PM)"}, {"type": "other", "role": null, "text": "1 unpaid 30-minute meal break"}, {"type": "other", "role": null, "text": "Unpaid"}, {"type": "other", "role": null, "text": "Factory/non-restaurant shifts over 8 hours"}, {"type": "other", "role": null, "text": "Additional 20-minute break (not applicable to restaurant shifts)"}, {"type": "other", "role": null, "text": "Paid"}, {"type": "table", "rows": [["Shift Length", "Break Entitlement", "Paid/Unpaid"], ["Shifts over 6 hours", "1 unpaid 30-minute meal break", "Unpaid"], ["Shifts between 5–6 hours (starting before 11 AM and extending past 2 PM)", "1 unpaid 30-minute meal break", "Unpaid"], ["Factory/non-restaurant shifts over 8 hours", "Additional 20-minute break (not applicable to restaurant shifts)", "Paid"]]}, {"type": "bullet", "text": "Meal breaks are scheduled by your manager. You may not take your break at a time that disrupts service without manager approval."}, {"type": "bullet", "text": "Break time begins when you leave your station and ends when you return. Do not clock out for your break — your manager will track it."}, {"type": "bullet", "text": "Cell phone use is permitted during breaks, in the designated break area only."}, {"type": "bullet", "text": "You must return from your break on time. Consistently extended breaks will be addressed through progressive discipline."}]'::jsonb, true, 21),
  (4, 'OPERATIONS AND COMPENSATION', 22, 'Spread of Hours Pay', '[{"type": "paragraph", "text": "Under New York State Labor Law, when an employee''s workday spans more than 10 hours from start to finish — including meal breaks — they are entitled to an additional hour of pay at the applicable minimum wage. This is called \"spread of hours\" pay."}, {"type": "paragraph", "text": "Example: If an employee works a shift from 11:00 AM to 12:00 AM (13 hours spread), they are entitled to one additional hour of minimum wage pay. Gothamhalal will calculate and pay spread of hours automatically on the applicable payroll cycle. If you believe a spread of hours situation was not compensated, contact Ahmed Mario Almugannahi immediately."}]'::jsonb, true, 22),
  (4, 'OPERATIONS AND COMPENSATION', 23, 'Overtime Policy', '[{"type": "paragraph", "text": "Gothamhalal complies with the Fair Labor Standards Act (FLSA) and New York State Labor Law regarding overtime. Any hours worked in excess of 40 hours in a workweek must be compensated at a rate of one and one-half (1.5) times your regular hourly rate."}, {"type": "bullet", "text": "Overtime must be approved in advance by your manager. Working overtime without authorization may result in disciplinary action."}, {"type": "bullet", "text": "You will be compensated for all overtime hours worked, including unauthorized overtime, but you may be disciplined for working overtime without authorization."}]'::jsonb, true, 23),
  (4, 'OPERATIONS AND COMPENSATION', 24, 'New York State Paid Sick Leave', '[{"type": "paragraph", "text": "In accordance with the New York State Paid Sick Leave Law (NY SSL §196-b), all Gothamhalal employees are entitled to paid sick leave benefits as follows:"}, {"type": "paragraph", "text": "<b>Accrual</b>"}, {"type": "bullet", "text": "Employees accrue 1 hour of paid sick leave for every 30 hours worked"}, {"type": "bullet", "text": "Employees may accrue up to 56 hours of paid sick leave per calendar year"}, {"type": "bullet", "text": "Accrual begins on the first day of employment"}, {"type": "bullet", "text": "Paid sick leave may be used beginning after 120 calendar days of employment"}, {"type": "paragraph", "text": "<b>Permitted Uses</b>"}, {"type": "paragraph", "text": "Paid sick leave may be used for:"}, {"type": "bullet", "text": "Your own mental or physical illness, injury, health condition, or preventive care"}, {"type": "bullet", "text": "Care for a family member (child, parent, spouse, domestic partner, sibling, grandparent, grandchild, or any individual you care for) with a mental or physical illness, injury, or health condition"}, {"type": "bullet", "text": "Absence related to domestic violence, stalking, sexual assault, or human trafficking of you or a family member"}, {"type": "paragraph", "text": "<b>How to Request Sick Leave</b>"}, {"type": "bullet", "text": "1. Notify your manager as soon as possible — ideally following the call-out procedure (2 hours before your shift)"}, {"type": "bullet", "text": "2. Indicate that you will be using paid sick leave"}, {"type": "bullet", "text": "3. You are not required to provide documentation of illness for absences of 3 or fewer days"}, {"type": "bullet", "text": "4. For absences of 4 or more consecutive days, documentation from a healthcare provider may be requested"}, {"type": "paragraph", "text": "<b>Carry-Over and Payout</b>"}, {"type": "bullet", "text": "Unused sick leave may be carried over to the following year up to a maximum of 56 hours"}, {"type": "bullet", "text": "Gothamhalal is not required to pay out unused sick leave upon separation of employment"}]'::jsonb, true, 24),
  (5, 'DISCIPLINE AND SEPARATION', 25, 'Progressive Discipline Policy', '[{"type": "paragraph", "text": "Gothamhalal believes in fair, consistent, and documented accountability. The progressive discipline system ensures that employees have the opportunity to understand what is expected, receive clear feedback, and correct their behavior before more serious action is taken."}, {"type": "paragraph", "text": "<b>The 3-Strike System</b>"}, {"type": "other", "role": null, "text": "Strike"}, {"type": "other", "role": null, "text": "Action"}, {"type": "other", "role": null, "text": "What It Means"}, {"type": "other", "role": null, "text": "Strike 1"}, {"type": "other", "role": null, "text": "Written Warning"}, {"type": "other", "role": null, "text": "A formal written notice documenting the specific violation, the expected corrective behavior, and the consequence of future violations. The employee and manager both sign the form. A copy is placed in the employee''s file."}, {"type": "other", "role": null, "text": "Strike 2"}, {"type": "other", "role": null, "text": "Final Written Warning"}, {"type": "other", "role": null, "text": "A second formal written notice confirming that the employee has failed to correct the behavior addressed in Strike 1, or has committed an additional violation. Failure to correct behavior after Strike 2 will result in termination."}, {"type": "other", "role": null, "text": "Strike 3"}, {"type": "other", "role": null, "text": "Termination"}, {"type": "other", "role": null, "text": "The employee is separated from Gothamhalal. A Termination Checklist and Notice form is completed. The employee receives written confirmation of termination and instructions for return of uniform and company property."}, {"type": "table", "rows": [["Strike", "Action", "What It Means"], ["Strike 1", "Written Warning", "A formal written notice documenting the specific violation, the expected corrective behavior, and the consequence of future violations. The employee and manager both sign the form. A copy is placed in the employee''s file."], ["Strike 2", "Final Written Warning", "A second formal written notice confirming that the employee has failed to correct the behavior addressed in Strike 1, or has committed an additional violation. Failure to correct behavior after Strike 2 will result in termination."], ["Strike 3", "Termination", "The employee is separated from Gothamhalal. A Termination Checklist and Notice form is completed. The employee receives written confirmation of termination and instructions for return of uniform and company property."]]}, {"type": "paragraph", "text": "<b>Documentation Requirement</b>"}, {"type": "paragraph", "text": "Every step of the progressive discipline process must be documented in writing. If it is not documented, it did not happen. Verbal warnings alone do not constitute a disciplinary strike, though they may be recorded as coaching conversations. Disciplinary documentation is maintained in the employee''s personnel file and is considered confidential."}, {"type": "paragraph", "text": "<b>Examples of Violations Subject to Progressive Discipline</b>"}, {"type": "bullet", "text": "Tardiness (three times in 30 days triggers Strike 1)"}, {"type": "bullet", "text": "Cell phone on the floor during shift (second offense triggers Strike 1)"}, {"type": "bullet", "text": "Failure to follow uniform or hygiene standards (after verbal correction)"}, {"type": "bullet", "text": "Failure to follow SOPs after training completion"}, {"type": "bullet", "text": "Rude or unprofessional conduct toward coworkers or customers"}, {"type": "bullet", "text": "Excessive absences or attendance pattern violations"}, {"type": "bullet", "text": "Failure to complete assigned cleaning, prep, or closing duties"}, {"type": "bullet", "text": "Smoking or vaping on premises or in uniform"}, {"type": "bullet", "text": "Failure to follow cash handling procedures (non-theft)"}, {"type": "bullet", "text": "Violation of the social media policy (non-confidential)"}, {"type": "paragraph", "text": "<b>Severity Escalation</b>"}, {"type": "paragraph", "text": "Gothamhalal reserves the right to skip progressive discipline steps for violations of greater severity. A second violation that is significantly more serious than the first, or conduct that poses an immediate risk to the team or brand, may result in termination after Strike 1 or without a prior strike at management discretion, in consultation with the Director of Operations."}]'::jsonb, true, 25),
  (5, 'DISCIPLINE AND SEPARATION', 26, 'Immediate Termination Offenses', '[{"type": "paragraph", "text": "Certain conduct is so serious that it warrants immediate termination without progressive discipline. Any employee found to have engaged in the following will be terminated immediately:"}, {"type": "other", "role": null, "text": "Offense"}, {"type": "other", "role": null, "text": "Description"}, {"type": "other", "role": null, "text": "Theft"}, {"type": "other", "role": null, "text": "Stealing money, product, inventory, tips, or any property belonging to Gothamhalal, a coworker, or a customer. This includes consuming product without authorization, undercounting the drawer, and giving unauthorized discounts."}, {"type": "other", "role": null, "text": "Harassment or Discrimination"}, {"type": "other", "role": null, "text": "Any confirmed act of sexual harassment, racial harassment, or discrimination that violates Gothamhalal''s anti-harassment policy and applicable law."}, {"type": "other", "role": null, "text": "Fighting"}, {"type": "other", "role": null, "text": "Engaging in physical violence, initiating a fight, or making credible physical threats against any person on company premises or while in uniform."}, {"type": "other", "role": null, "text": "Compromising Halal Standards"}, {"type": "other", "role": null, "text": "Deliberately tampering with, contaminating, or misrepresenting halal food integrity. Knowingly using non-halal ingredients or allowing cross-contamination without reporting it."}, {"type": "other", "role": null, "text": "Second No Call / No Show"}, {"type": "other", "role": null, "text": "Failing to report for a scheduled shift without any prior notification for a second time within any 12-month period."}, {"type": "other", "role": null, "text": "Falsifying Records"}, {"type": "other", "role": null, "text": "Altering, falsifying, or misrepresenting any company document including time records, cash logs, temperature logs, or HR documents."}, {"type": "other", "role": null, "text": "Gross Insubordination"}, {"type": "other", "role": null, "text": "Openly refusing to follow a lawful and reasonable directive from management, or verbally or physically threatening a manager."}, {"type": "other", "role": null, "text": "Drug or Alcohol Use on Duty"}, {"type": "other", "role": null, "text": "Reporting to work impaired by drugs or alcohol, or consuming drugs or alcohol while on the clock."}, {"type": "table", "rows": [["Offense", "Description"], ["Theft", "Stealing money, product, inventory, tips, or any property belonging to Gothamhalal, a coworker, or a customer. This includes consuming product without authorization, undercounting the drawer, and giving unauthorized discounts."], ["Harassment or Discrimination", "Any confirmed act of sexual harassment, racial harassment, or discrimination that violates Gothamhalal''s anti-harassment policy and applicable law."], ["Fighting", "Engaging in physical violence, initiating a fight, or making credible physical threats against any person on company premises or while in uniform."], ["Compromising Halal Standards", "Deliberately tampering with, contaminating, or misrepresenting halal food integrity. Knowingly using non-halal ingredients or allowing cross-contamination without reporting it."], ["Second No Call / No Show", "Failing to report for a scheduled shift without any prior notification for a second time within any 12-month period."], ["Falsifying Records", "Altering, falsifying, or misrepresenting any company document including time records, cash logs, temperature logs, or HR documents."], ["Gross Insubordination", "Openly refusing to follow a lawful and reasonable directive from management, or verbally or physically threatening a manager."], ["Drug or Alcohol Use on Duty", "Reporting to work impaired by drugs or alcohol, or consuming drugs or alcohol while on the clock."]]}]'::jsonb, true, 26),
  (5, 'DISCIPLINE AND SEPARATION', 27, 'Termination Policy', '[{"type": "paragraph", "text": "When an employee''s employment ends — whether voluntarily through resignation or involuntarily through termination — the following process applies:"}, {"type": "bullet", "text": "The employee will receive written confirmation of the termination or acceptance of resignation"}, {"type": "bullet", "text": "All Gothamhalal property including uniforms, keys, access badges, and any equipment must be returned on the final day of employment. Failure to return property may result in deductions from final pay as permitted by New York State law."}, {"type": "bullet", "text": "Final wages will be paid no later than the next regularly scheduled payday following separation, in compliance with New York State law"}, {"type": "bullet", "text": "Information about COBRA continuation coverage and any benefit continuation rights will be provided in writing upon separation"}, {"type": "bullet", "text": "References will confirm dates of employment and position held. Gothamhalal''s policy is to provide neutral employment verifications."}, {"type": "heading", "level": "h1", "text": "GOTHAMHALAL EMPLOYEE HANDBOOK ACKNOWLEDGEMENT"}, {"type": "paragraph", "text": "I, the undersigned, acknowledge that I have received, read, and understand the Gothamhalal Employee Handbook, Version 1.0. I understand that this handbook outlines the policies, expectations, and standards of Gothamhalal, and I agree to comply with all policies contained herein."}, {"type": "paragraph", "text": "I understand that:"}, {"type": "bullet", "text": "This handbook is not a contract of employment and does not alter my at-will employment status"}, {"type": "bullet", "text": "Gothamhalal may modify, update, or revise handbook policies at any time, with reasonable notice to employees"}, {"type": "bullet", "text": "It is my responsibility to stay current with any policy updates communicated by management"}, {"type": "bullet", "text": "Violations of the policies in this handbook may result in progressive discipline up to and including immediate termination"}, {"type": "bullet", "text": "I have been given the opportunity to ask questions about any policy and have had those questions answered to my satisfaction"}, {"type": "paragraph", "text": "A copy of this signed acknowledgement will be retained in your employee personnel file. You may request a copy of this handbook at any time from management."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  EH-001 — Employee Handbook v1.0 — Effective January 1, 2025  ·  CONFIDENTIAL"}]'::jsonb, true, 27);
